import{_ as a,o as r,c as e,a0 as d}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"AI情报日报 2026-07-20","description":"","frontmatter":{"type":"page","title":"AI情报日报 2026-07-20","tags":["ai","daily-report","情报"],"created":"2026-07-20T00:00:00.000Z"},"headers":[],"relativePath":"daily/ai-report-2026-07-20.md","filePath":"daily/ai-report-2026-07-20.md"}'),o={name:"daily/ai-report-2026-07-20.md"};function n(i,t,s,h,l,c){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="ai情报日报-2026-07-20" tabindex="-1">AI情报日报 2026-07-20 <a class="header-anchor" href="#ai情报日报-2026-07-20" aria-label="Permalink to &quot;AI情报日报 2026-07-20&quot;">​</a></h1><blockquote><p>覆盖时段：2026-07-19 ~ 2026-07-20 | 来源：AI HOT + 小红书爆款</p></blockquote><hr><h2 id="ai-hot-精选" tabindex="-1">AI HOT 精选 <a class="header-anchor" href="#ai-hot-精选" aria-label="Permalink to &quot;AI HOT 精选&quot;">​</a></h2><h3 id="🚀-模型发布-更新" tabindex="-1">🚀 模型发布/更新 <a class="header-anchor" href="#🚀-模型发布-更新" aria-label="Permalink to &quot;🚀 模型发布/更新&quot;">​</a></h3><h4 id="_1-qwen3-8-开源发布-2-4t-参数模型上线" tabindex="-1">1. Qwen3.8 开源发布，2.4T 参数模型上线 <a class="header-anchor" href="#_1-qwen3-8-开源发布-2-4t-参数模型上线" aria-label="Permalink to &quot;1. Qwen3.8 开源发布，2.4T 参数模型上线&quot;">​</a></h4><p>通义千问发布 Qwen3.8-Max-Preview，拥有 2.4T 海量参数，是目前最强大的模型之一，仅次于 Fable 5。已在阿里云 Token Plan、Qoder 等平台亮相，即将开源权重。 🔗 <a href="https://x.com/Alibaba_Qwen/status/2078754377473601787" target="_blank" rel="noreferrer">X：通义千问</a></p><h4 id="_2-昆仑万维宣布2026为-世界模型元年-发布-matrix-game-3-5" tabindex="-1">2. 昆仑万维宣布2026为&quot;世界模型元年&quot;，发布 Matrix-Game 3.5 <a class="header-anchor" href="#_2-昆仑万维宣布2026为-世界模型元年-发布-matrix-game-3-5" aria-label="Permalink to &quot;2. 昆仑万维宣布2026为&quot;世界模型元年&quot;，发布 Matrix-Game 3.5&quot;">​</a></h4><p>昆仑万维在 WAIC 上发布 Matrix-Game 3.5 世界模型、Mureka v9.5 与 O3 音乐模型。Matrix-Game 3.5 实现 Patch 级记忆注入，5B 模型在 720p 分辨率下单卡可达 20FPS 实时生成，核心架构已开源。 🔗 <a href="https://mp.weixin.qq.com/s/LidvGePhOOoUY3KTor_w9g" target="_blank" rel="noreferrer">公众号：昆仑万维</a></p><h4 id="_3-面壁智能开源-minicpm-robot-具身智能模型系列" tabindex="-1">3. 面壁智能开源 MiniCPM-Robot 具身智能模型系列 <a class="header-anchor" href="#_3-面壁智能开源-minicpm-robot-具身智能模型系列" aria-label="Permalink to &quot;3. 面壁智能开源 MiniCPM-Robot 具身智能模型系列&quot;">​</a></h4><p>面壁智能开源首个具身 AI 模型系列 MiniCPM-Robot，包含 1.5B 参数的通用 VLA 模型 MiniCPM-RobotManip 和目标跟踪模型 MiniCPM-RobotTrack，同时发布高性能推理框架 PhyAI，旨在让机器人实现理解、记忆与行动。 🔗 <a href="https://x.com/OpenBMB/status/2078839529591759025" target="_blank" rel="noreferrer">X：面壁智能 OpenBMB</a></p><h4 id="_4-minicpm5-2b-发布-4b以下全球性能第一" tabindex="-1">4. MiniCPM5-2B 发布：4B以下全球性能第一 <a class="header-anchor" href="#_4-minicpm5-2b-发布-4b以下全球性能第一" aria-label="Permalink to &quot;4. MiniCPM5-2B 发布：4B以下全球性能第一&quot;">​</a></h4><p>面壁智能联合 OpenBMB 发布端侧模型 MiniCPM5-2B，AA-Index 榜单 4B 以下模型最高分 17 分，超越 Qwen3.5-2B 等竞品。支持混合思考与 512K 上下文，已完成华为昇腾、英伟达等 9 款芯片的 Day0 适配。 🔗 <a href="https://mp.weixin.qq.com/s/rjFxrUylyGMqa5QtgypCdw" target="_blank" rel="noreferrer">公众号：面壁智能</a></p><hr><h3 id="🛠️-产品发布-更新" tabindex="-1">🛠️ 产品发布/更新 <a class="header-anchor" href="#🛠️-产品发布-更新" aria-label="Permalink to &quot;🛠️ 产品发布/更新&quot;">​</a></h3><h4 id="_5-transcribe-cpp-发布-跨平台语音转录库" tabindex="-1">5. transcribe.cpp 发布：跨平台语音转录库 <a class="header-anchor" href="#_5-transcribe-cpp-发布-跨平台语音转录库" aria-label="Permalink to &quot;5. transcribe.cpp 发布：跨平台语音转录库&quot;">​</a></h4><p>基于 ggml 的语音转录库 v0.1.0 发布，支持 16 个 ASR 模型族（60+ 模型），通过 Vulkan、Metal、CUDA 和 TinyBLAS 实现 GPU 加速。 🔗 <a href="https://workshop.cjpais.com/projects/transcribe-cpp" target="_blank" rel="noreferrer">Hacker News</a></p><h4 id="_6-chatgpt-work-功能上线-建站、邮件、文档处理" tabindex="-1">6. ChatGPT Work 功能上线：建站、邮件、文档处理 <a class="header-anchor" href="#_6-chatgpt-work-功能上线-建站、邮件、文档处理" aria-label="Permalink to &quot;6. ChatGPT Work 功能上线：建站、邮件、文档处理&quot;">​</a></h4><p>ChatGPT Work 支持创建和托管网站、管理电子邮件、总结海量文档、制作文档/表格/幻灯片。已面向 Plus/Pro/Business/Enterprise 用户开放。 🔗 <a href="https://x.com/thsottiaux/status/2078697631019303273" target="_blank" rel="noreferrer">X：Tibo</a></p><hr><h3 id="🌐-行业动态" tabindex="-1">🌐 行业动态 <a class="header-anchor" href="#🌐-行业动态" aria-label="Permalink to &quot;🌐 行业动态&quot;">​</a></h3><h4 id="_7-黄仁勋访日-nvidia-联手日本打造物理-ai-时代" tabindex="-1">7. 黄仁勋访日：Nvidia 联手日本打造物理 AI 时代 <a class="header-anchor" href="#_7-黄仁勋访日-nvidia-联手日本打造物理-ai-时代" aria-label="Permalink to &quot;7. 黄仁勋访日：Nvidia 联手日本打造物理 AI 时代&quot;">​</a></h4><p>Nvidia CEO 访日期间，宣布为日本建设 &quot;Vera Rubin AI 工厂&quot;，配备 13,750 颗 Vera CPU 和 27,500 颗 Rubin GPU，预计 2028 年投运。同时推进 Cosmos 机器人联盟落地。 🔗 <a href="https://techcrunch.com/2026/07/19/what-to-watch-for-after-jensen-huangs-japan-visit" target="_blank" rel="noreferrer">TechCrunch</a></p><hr><h3 id="💡-技巧与观点" tabindex="-1">💡 技巧与观点 <a class="header-anchor" href="#💡-技巧与观点" aria-label="Permalink to &quot;💡 技巧与观点&quot;">​</a></h3><h4 id="_8-ai-热潮正在瓦解全球决策机制" tabindex="-1">8. AI 热潮正在瓦解全球决策机制 <a class="header-anchor" href="#_8-ai-热潮正在瓦解全球决策机制" aria-label="Permalink to &quot;8. AI 热潮正在瓦解全球决策机制&quot;">​</a></h4><p>一位资深从业者观察到，全球公私机构陷入集体性 AI 狂热，但其团队所见的所有 AI 项目均以失败告终（成功率 0%）。失败原因常与 LLM 能力无关，而是企业本就难以有效运行软件项目，AI 项目叠加了额外风险。内部聊天机器人几乎无人使用。 🔗 <a href="https://ludic.mataroa.blog/blog/ai-mania-is-eviscerating-global-decision-making" target="_blank" rel="noreferrer">Hacker News 热门</a></p><hr><h2 id="小红书爆款-top-10" tabindex="-1">小红书爆款 TOP 10 <a class="header-anchor" href="#小红书爆款-top-10" aria-label="Permalink to &quot;小红书爆款 TOP 10&quot;">​</a></h2><blockquote><p>数据日期：2026-07-17 | 来源：RedFox 趋势榜</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>作者</th><th>粉丝</th><th>标题</th><th>互动量</th><th>点赞</th><th>收藏</th></tr></thead><tbody><tr><td>1</td><td><strong>OK妹</strong></td><td>92w+</td><td>(搞笑母子)</td><td><strong>36w+</strong></td><td>32w+</td><td>3w+</td></tr><tr><td>2</td><td><strong>小然叭叭叭</strong></td><td>10w+</td><td>小说妹别偷笑了～</td><td><strong>24w+</strong></td><td>16w+</td><td>7w+</td></tr><tr><td>3</td><td><strong>C位乖乖兔</strong></td><td>27w+</td><td>反派不补刀 原来是听爽了</td><td><strong>17w+</strong></td><td>14w+</td><td>2w+</td></tr><tr><td>4</td><td><strong>娱乐西施王美丽</strong></td><td>21w+</td><td>请允许这个世界有亲情的存在吧</td><td><strong>13w+</strong></td><td>12w+</td><td>5262</td></tr><tr><td>5</td><td><strong>王哥说车</strong></td><td>5w+</td><td>被人打了，记住这个维权流程</td><td><strong>12w+</strong></td><td>6w+</td><td>6w+</td></tr><tr><td>6</td><td><strong>全球创意榜</strong></td><td>22w+</td><td>BBC太会讽刺了，性同意不是穿出来的</td><td><strong>11w+</strong></td><td>10w+</td><td>7487</td></tr><tr><td>7</td><td><strong>屿甜</strong></td><td>7(素人)</td><td>大学生真是狠狠共鸣了！</td><td><strong>10w+</strong></td><td>9w+</td><td>7320</td></tr><tr><td>8</td><td><strong>王易燃</strong></td><td>15w+</td><td>约会当着crush面前随意大小展…</td><td><strong>10w+</strong></td><td>9w+</td><td>5159</td></tr><tr><td>9</td><td><strong>刘安娜会画画</strong></td><td>8w+</td><td>外面的社会可没有人惯着你 (AI视频)</td><td><strong>9w+</strong></td><td>7w+</td><td>1w+</td></tr><tr><td>10</td><td><strong>淇儿ki</strong></td><td>6w+</td><td>福州鼓山缆车大震惊。。。好刺激</td><td><strong>9w+</strong></td><td>8w+</td><td>3994</td></tr></tbody></table><p><strong>亮点观察：</strong></p><ul><li>🏆 榜首 <strong>OK妹</strong> 以 36w+ 互动量断层领先，搞笑/家庭类内容持续强势</li><li>📌 <strong>王哥说车</strong>（5w粉）用实用维权知识撬动 12w+ 互动，收藏量高达 6w+</li><li>🌟 <strong>屿甜</strong>（仅7粉丝）素人爆款典范，大学生共鸣类内容 10w+ 互动</li><li>🤖 <strong>刘安娜会画画</strong> AI视频内容获 9w+ 互动，AI+搞笑赛道有潜力</li><li>🎭 搞笑/家庭/情感类内容占主导，实用干货类收藏率极高</li></ul><hr><p><em>数据来源：AI HOT (<a href="https://aihot.virxact.com" target="_blank" rel="noreferrer">https://aihot.virxact.com</a>) · RedFox 红狐狸</em></p><p><em>生成时间：2026-07-20 17:18 BJT</em></p>',36)])])}const b=a(o,[["render",n]]);export{g as __pageData,b as default};
